<script lang="ts">
	import type { PageProps } from "./$types";
	import { goto } from "$app/navigation";
	import Icon from "$lib/components/Icon.svelte";
	import AgentPresence from "$lib/components/AgentPresence.svelte";
	import { getLibraryItemDetail } from "./library-detail.remote";
	let { data }: PageProps = $props();
	// svelte-ignore state_referenced_locally
	const detailQuery=getLibraryItemDetail(data.itemId);
	const detail=$derived(detailQuery.current);
	let version=$state<number|null>(null);
	const shown=$derived(version===null?detail?.item:detail?.revisions.find((revision)=>revision.version===version)?.item??detail?.item);
	const shownRevision=$derived(detail?.revisions.find((revision)=>revision.version===(version??detail.item.version)));
	function open(targetId:string){void goto(`/library/${encodeURIComponent(targetId)}`);version=null;}
</script>
<svelte:head><title>{shown?.title??"Library item"} · Lab Console</title></svelte:head>
<nav class="crumb" aria-label="Breadcrumb"><a href="/library"><Icon name="arrow-left" size={14}/>Library</a><span>/</span><span>{shown?.title??"Loading item…"}</span></nav>
{#if !detail && detailQuery.loading}<main class="skeleton" aria-label="Loading Library item"><div></div><div></div><div></div></main>
{:else if detail && shown}
<main class="item-page">
	{#if shown.status.toUpperCase()==="CONFLICT"}<aside class="conflict" role="alert"><Icon name="triangle-alert" size={18}/><div><strong>Two writers disagree. Adjudicate.</strong><p>The competing status values remain recorded; no edit won silently.</p></div></aside>{/if}
	<header class="title"><div><Icon name="book-open" size={18}/><h1>{shown.title}</h1></div><p>{shown.kind} in {shown.project} · {shown.scope}</p></header>
	<div class="chips"><span>{shown.kind}</span><span class:warn={shown.status.toUpperCase()==="CONFLICT"}>{shown.status}</span><span><Icon name="shield" size={11}/>{shown.protection??"unknown"}</span><span>conf {shown.confidence?.toFixed(2)??"—"}</span></div>
	<section class="body"><p>{shown.body}</p></section>
	<div class="columns"><section><h2>Links out</h2>{#each detail.links.filter((link)=>link.direction==="out") as link, __eachKey33 (__eachKey33)}<button class:broken={!link.target} class="link-row" onclick={()=>{ if(link.target) open(link.targetId); }} disabled={!link.target}><Icon name="arrow-right" size={14}/><code>{link.rel}</code><span><b>{link.target?.title??"Target weeded"}</b>{#if link.reason}<small>{link.reason}</small>{/if}</span></button>{:else}<p class="empty">No outgoing links filed.</p>{/each}</section><section><h2>Links in</h2>{#each detail.links.filter((link)=>link.direction==="in") as link, __eachKey34 (__eachKey34)}<button class:broken={!link.target} class="link-row" onclick={()=>{ if(link.target) open(link.targetId); }} disabled={!link.target}><Icon name="arrow-left" size={14}/><code>{link.rel}</code><span><b>{link.target?.title??"Target weeded"}</b>{#if link.reason}<small>{link.reason}</small>{/if}</span></button>{:else}<p class="empty">No incoming links filed.</p>{/each}</section></div>
	<section class="provenance"><h2>Provenance</h2><div><span><AgentPresence handle={shown.creator} label="created-by-agent:"/></span><span>responsible-human: {detail.responsibleHuman}</span><span>handed-off-to-agent: {shown.handedOffTo??"none"}</span></div></section>
	<footer class="version"><div><Icon name="history" size={16}/><div><strong>Version {shown.version}</strong><small>tx_from {shownRevision?.txFrom??detail.txFrom}</small></div></div><label><span>What did we believe when?</span><select value={version??detail.item.version} onchange={(event)=>version=Number(event.currentTarget.value)}>{#each detail.revisions as revision, __eachKey35 (__eachKey35)}<option value={revision.version}>v{revision.version} · {new Date(revision.txFrom).toLocaleString()}</option>{/each}</select></label><span class="history-count">{detail.revisions.length} tx {detail.revisions.length===1?"entry":"entries"}</span></footer>
</main>{/if}
