y:block}.link-row b{font-size:.75rem}.link-row small{margin-top:var(--s-1);color:var(--text-3);font-size:.6875rem}.link-row.broken{color:var(--danger-text);opacity:1}.empty{padding:var(--s-3) 0;color:var(--text-3);font-size:.75rem}.provenance{margin-top:var(--s-3)}.provenance div{display:flex;flex-wrap:wrap;gap:var(--s-1)}.version{position:sticky;bottom:var(--s-2);display:flex;align-items:center;gap:var(--s-3);margin-top:var(--s-4);padding:var(--s-2) var(--s-3);background:var(--s2);box-shadow:inset 0 0 0 1px var(--rule);border-radius:var(--r-sm)}.version>div{display:flex;align-items:center;gap:var(--s-2)}.version strong,.version small{display:block}.version strong{font-size:.75rem}.version small,.history-count,.version label span{color:var(--text-3);font:400 .6875rem var(--mono)}.version label{display:flex;align-items:center;gap:var(--s-2);margin-inline-start:auto}.version select{min-height:32px;border:0;border-radius:var(--r-sm);background:var(--s1);color:var(--text);padding:0 var(--s-2);font:400 .6875rem var(--mono)}.skeleton{max-width:1008px;margin:var(--s-4) auto}.skeleton div{height:40px;margin-bottom:var(--s-3);background:var(--s2);animation:pulse 1.4s ease-in-out infinite}.skeleton div:nth-child(2){height:176px}.skeleton div:nth-child(3){width:60%}@keyframes detail-in{from{opacity:.72;transform:translateY(2px)}}@keyframes pulse{50%{opacity:.55}}@media(max-width:767px){.columns{grid-template-columns:1fr}.version{align-items:flex-start;flex-wrap:wrap}.version label{order:3;width:100%;margin:0;align-items:flex-start;flex-direction:column}.version select{width:100%}.history-count{margin-inline-start:auto}}@media(prefers-reduced-motion:reduce){.item-page,.skeleton div{animation:none}.link-row{transition:none}}
